5	export interface Item {
6	  type: string;
7	}
8	
9	const PROCESSING_FEE = 5;
10	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
11	
12	const BASE_PRICES: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	const BLOCK_PRICE: Record<string, number> = {
23	  rune: 60,
24	  moonstone: 60,
25	};
26	
27	export function quote(_customer: Customer, items: Item[]): number {
28	  let total = 0;
29	  const componentCounts: Record<string, number> = {};
30	  for (const item of items) {
31	    if (COMPONENT_TYPES.has(item.type)) {
32	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
33	      continue;
34	    }
35	    const base = BASE_PRICES[item.type] ?? 0;
36	    total += base + base * FIRST_INSURANCE_SURCHARGE_RATE;
37	  }
38	  for (const type of Object.keys(componentCounts)) {
39	    const count = componentCounts[type];
40	    const unitPrice = BASE_PRICES[type] ?? 0;
41	    const base = count === 3 ? BLOCK_PRICE[type] : unitPrice * count;
42	    total += base + base * FIRST_INSURANCE_SURCHARGE_RATE;
43	  }
44	  total += PROCESSING_FEE;
45	  return Math.ceil(total);
46	}
47	
48	export function claim(): unknown {
49	  return undefined;
50	}
